// // This D flip-flop captures the value of the D input on the falling edge of the clock and holds the value until the next falling edge.
module d_flip_flop (
    input wire clk,
    input wire rst,
    input wire d,
    output reg q
);
    always @(posedge clk or posedge rst) begin
        if (rst)
            q <= 0;
        else
            q <= d;
    end
endmodule
